mapper.select:
SELECT A.NROUT_HIST_MST_SEQ -- 라우팅 이력관리 MST SEQ , A.PTELNET_IP -- TELNET_IP , A.SHOST_NM -- 호스트명 , A.SRESULT_MSG -- 결과메세지 , A.NLVL_BAS_SEQ -- 계위_BAS_SEQ , A.NLVL_MST_SEQ -- 계위_Mst_seq , A.SPROCESS_YN -- 진행_여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.RNUM FROM ( SELECT A.NROUT_HIST_MST_SEQ -- 라우팅 이력관리 MST SEQ , A.PTELNET_IP -- TELNET_IP , A.SHOST_NM -- 호스트명 , A.SRESULT_MSG -- 결과메세지 , A.NLVL_BAS_SEQ -- 계위_BAS_SEQ , A.NLVL_MST_SEQ -- 계위_Mst_seq , A.SPROCESS_YN -- 진행_여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , ROWNUM RNUM FROM ( SELECT A.NROUT_HIST_MST_SEQ -- 라우팅 이력관리 MST SEQ , A.PTELNET_IP -- TELNET_IP , A.SHOST_NM -- 호스트명 , A.SRESULT_MSG -- 결과메세지 , A.NLVL_BAS_SEQ -- 계위_BAS_SEQ , A.NLVL_MST_SEQ -- 계위_Mst_SEQ , A.SPROCESS_YN -- 진행_여부 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_INTGRM_ROUT_HIST_MST A -- 라우팅 이력관리 MST WHERE 1=1
AND A.PTELNET_IP = #{ptelnetIp, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
AND A.SHOST_NM ILIKE '%' || #{shostNm, jdbcType=VARCHAR} || '%'
AND TO_CHAR(A.DCREATE_DT, 'YYYY-MM-DD') >= #{searchBgnDe, jdbcType=TIMESTAMP}
AND TO_CHAR(A.DMODIFY_DT, 'YYYY-MM-DD') <= #{searchEndDe, jdbcType=TIMESTAMP}
AND A.SPROCESS_YN = #{sprocessYn, jdbcType=CHAR}
AND A.SRESULT_MSG ILIKE '%' || #{sresultMsg, jdbcType=VARCHAR} || '%'
ORDER BY A.NROUT_HIST_MST_SEQ DESC ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount 
FROM MST.TB_INTGRM_ROUT_HIST_MST A	 -- 라우팅 이력관리 MST 
WHERE 1=1 

		AND A.PTELNET_IP = #{ptelnetIp, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		AND A.SHOST_NM ILIKE '%' || #{shostNm, jdbcType=VARCHAR} || '%'


		AND TO_CHAR(A.DCREATE_DT, 'YYYY-MM-DD') >=  #{searchBgnDe, jdbcType=TIMESTAMP}


		AND TO_CHAR(A.DMODIFY_DT, 'YYYY-MM-DD') <=  #{searchEndDe, jdbcType=TIMESTAMP}


		AND A.SPROCESS_YN = #{sprocessYn, jdbcType=CHAR}


		AND A.SRESULT_MSG ILIKE '%' || #{sresultMsg, jdbcType=VARCHAR} || '%'

mapper.update:
UPDATE
	MST.TB_INTGRM_ROUT_HIST_MST A
SET
	A.DMODIFY_DT = SYSDATE

		, A.SRESULT_MSG = #{sresultMsg, jdbcType=VARCHAR}


		, A.SPROCESS_YN = #{sprocessYn, jdbcType=CHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

WHERE 1=1
	AND A.NROUT_HIST_MST_SEQ = #{nroutHistMstSeq, jdbcType=BIGINT}
